#include <bits/stdc++.h>
using namespace std;
const int N=210;
bool dp[N][N][5],flag[5][5][5];
int a[5];
string s;
int fun(char c)
{
    if(c=='W') return 1;
    if(c=='I') return 2;
    if(c=='N') return 3;
    return 4;
}
int main()
{
    for(int i=1;i<=4;i++) cin>>a[i];
    for(int i=1;i<=4;i++)
    {
        for(int j=1;j<=a[i];j++)
        {
            string s1;
            cin>>s1;
            flag[i][fun(s1[0])][fun(s1[1])]=true;
        }
    }
    cin>>s;
    for(int i=0;i<s.size();i++) dp[i][i][fun(s[i])]=true;
    for(int len=2;len<=s.size();len++)
    {
        for(int l=0;l+len-1<s.size();l++)
        {
            int r=len+l-1;
            for(int i1=l;i1<r;i1++)
            {
                for(int i2=1;i2<=4;i2++)
                {
                    for(int i3=1;i3<=4;i3++)
                    {
                        for(int i4=1;i4<=4;i4++)
                        {
                            if(flag[i2][i3][i4]&&dp[l][i1][i3]&&dp[i1+1][r][i4])
                            {
                                dp[l][r][i2]=true;
                            }
                        }
                    }
                }
            }
        }
    }
    bool flag=true;
    if(dp[0][s.size()-1][1])
    {
        flag=false;
        cout<<'W';
    }
    if(dp[0][s.size()-1][2])
    {
        flag=false;
        cout<<'I';
    }
    if(dp[0][s.size()-1][3])
    {
        flag=false;
        cout<<'N';
    }
    if(dp[0][s.size()-1][4])
    {
        flag=false;
        cout<<'G';
    }
    if(flag) cout<<"The name is wrong!";
    return 0;
}
